"<div>\n<i class=\"NoteType\">\n\u0417\u0430\u043c\u0435\u0442\u043a\u0430 \u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0435\n</i>\n<div class=\"grampsstylednote\">\n<p>\n\"\u0441\u0442\u0430\u0440\u0448\u0438\u0439 \u0431\u0440\u0430\u0442, \u0431\u044b\u043b \u0438\u0433\u0440\u043e\u043a, \u043f\u0440\u043e\u0438\u0433\u0440\u0430\u043b \u0432\u0441\u0451 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u0438 \u043f\u0440\u0430\u0431\u0430\u0431\u0443\u0448\u043a\u0430 \u0441 \u043c\u043b\u0430\u0434\u0448\u0438\u043c \u0431\u0440\u0430\u0442\u043e\u043c <strong>\u0422\u043e\u043c\u0430\u0441\u043e\u0432</strong> \u043e\u0441\u0442\u0430\u043b\u0438\u0441\u044c \u0431\u0435\u0437 \u043a\u0440\u043e\u0432\u0430 \u0438 \u0441\u0440\u0435\u0434\u0441\u0442\u0432 (\u0412\u043e\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u0410\u0440\u0445\u0438\u043f\u043e\u0432\u043e\u0439 \u0421.\u0418. \u0441.8)\n</p>\n</div>\n</div>",
