"<div>\n<i class=\"NoteType\">\n\u0417\u0430\u043c\u0435\u0442\u043a\u0430 \u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0435\n</i>\n<div class=\"grampsstylednote\">\n<p>\n\u0413\u0430\u0440\u0438\u0431\u0438\u043d \u041f\u0435\u0442\u0440 \u0418\u0432\u0430\u043d\u043e\u0432\u0438\u0447<br />\n\u0420\u0430\u043d\u0435\u043d/\u043a\u043e\u043d\u0442\u0443\u0436\u0435\u043d. \u0418\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u043f\u0438\u0441\u043a\u0438 \u043f\u043e\u0442\u0435\u0440\u044c<br />\n\u2014 \u0421\u043f\u0438\u0441\u043e\u043a \u043f\u043e\u0442\u0435\u0440\u044c \u2014<br />\n\u0414\u043e\u043b\u0436\u043d\u043e\u0441\u0442\u044c/\u0417\u0432\u0430\u043d\u0438\u0435 \u0440\u044f\u0434\u043e\u0432\u043e\u0439 \u0412\u043e\u0438\u043d\u0441\u043a\u0430\u044f \u0447\u0430\u0441\u0442\u044c 122-\u0439 \u043f\u0435\u0445\u043e\u0442\u043d\u044b\u0439 \u0422\u0430\u043c\u0431\u043e\u0432\u0441\u043a\u0438\u0439 \u043f\u043e\u043b\u043a \u041c\u0435\u0441\u0442\u043e \u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f. \u0413\u0443\u0431\u0435\u0440\u043d\u0438\u044f \u041a\u043e\u0441\u0442\u0440\u043e\u043c\u0441\u043a\u0430\u044f \u0433\u0443\u0431. \u041c\u0435\u0441\u0442\u043e \u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f. \u0423\u0435\u0437\u0434 \u041a\u043e\u0441\u0442\u0440\u043e\u043c\u0441\u043a\u043e\u0439 \u0443\u0435\u0437\u0434 \u041c\u0435\u0441\u0442\u043e \u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f. \u0412\u043e\u043b\u043e\u0441\u0442\u044c \u041a\u043e\u0440\u044f\u043a\u043e\u0432\u0441\u043a\u0430\u044f \u0432\u043e\u043b. \u041f\u0440\u0438\u0447\u0438\u043d\u0430 \u0432\u044b\u0431\u044b\u0442\u0438\u044f \u0440\u0430\u043d\u0435\u043d/\u043a\u043e\u043d\u0442\u0443\u0436\u0435\u043d \u0414\u0430\u0442\u0430 \u0441\u043e\u0431\u044b\u0442\u0438\u044f 14.07.1916 \u0422\u0438\u043f \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0430 \u0418\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u043f\u0438\u0441\u043a\u0438 \u043f\u043e\u0442\u0435\u0440\u044c<br />\n\u0410\u0440\u0445\u0438\u0432 \u0420\u043e\u0441\u0441\u0438\u0439\u0441\u043a\u0438\u0439 \u0413\u043e\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0412\u043e\u0435\u043d\u043d\u043e-\u0438\u0441\u0442\u043e\u0440\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0430\u0440\u0445\u0438\u0432 \u0424\u043e\u043d\u0434 \u211616196, \u041e\u0441\u043e\u0431\u043e\u0435 \u0434\u0435\u043b\u043e\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u043e \u043f\u043e \u0441\u0431\u043e\u0440\u0443 \u0438 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0441\u0432\u0435\u0434\u0435\u043d\u0438\u0439 \u043e \u0432\u044b\u0431\u044b\u0432\u0448\u0438\u0445 \u0437\u0430 \u0441\u043c\u0435\u0440\u0442\u044c\u044e \u0438\u043b\u0438 \u0437\u0430 \u0440\u0430\u043d\u0430\u043c\u0438, \u0430 \u0442\u0430\u043a\u0436\u0435 \u043f\u0440\u043e\u043f\u0430\u0432\u0448\u0438\u0445 \u0431\u0435\u0437 \u0432\u0435\u0441\u0442\u0438 \u0432\u043e\u0438\u043d\u0441\u043a\u0438\u0445 \u0447\u0438\u043d\u0430\u0445, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044e\u0449\u0438\u0445 \u043f\u0440\u043e\u0442\u0438\u0432 \u043d\u0435\u043f\u0440\u0438\u044f\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u0445 \u0430\u0440\u043c\u0438\u0439 (1914 - 1918) \u041e\u043f\u0438\u0441\u044c \u21161, \u0418\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u043f\u0438\u0441\u043a\u0438 \u043f\u043e\u0442\u0435\u0440\u044c \u0441\u043e\u043b\u0434\u0430\u0442 \u0438 \u043e\u0444\u0438\u0446\u0435\u0440\u043e\u0432 1 \u043c\u0438\u0440\u043e\u0432\u043e\u0439 \u0432\u043e\u0439\u043d\u044b 1914-1918 \u0433\u0433. (\u043f\u043e \u043f\u043e\u043b\u043a\u0430\u043c \u0438 \u0431\u0440\u0438\u0433\u0430\u0434\u0430\u043c) \u0414\u0435\u043b\u043e \u2116254, \u0418\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u043f\u0438\u0441\u043a\u0438 \u043f\u043e\u0442\u0435\u0440\u044c \u0441\u043e\u043b\u0434\u0430\u0442 122 \u043f\u0435\u0445\u043e\u0442\u043d\u043e\u0433\u043e \u0422\u0430\u043c\u0431\u043e\u0432\u0441\u043a\u043e\u0433\u043e \u043f\u043e\u043b\u043a\u0430 \u0414\u043e\u043a\u0443\u043c\u0435\u043d\u0442 \u2116147, \u0421\u043f\u0438\u0441\u043e\u043a \u0432\u043e\u0438\u043d\u0441\u043a\u0438\u0445 \u0447\u0438\u043d\u043e\u0432 122 \u043f\u0435\u0445\u043e\u0442\u043d\u043e\u0433\u043e \u0422\u0430\u043c\u0431\u043e\u0432\u0441\u043a\u043e\u0433\u043e \u043f\u043e\u043b\u043a\u0430, \u0443\u0431\u0438\u0442\u044b\u0445, \u043f\u0440\u043e\u043f\u0430\u0432\u0448\u0438\u0445 \u0431\u0435\u0437 \u0432\u0435\u0441\u0442\u0438 \u0438 \u0432\u0437\u044f\u0442\u044b\u0445 \u0432 \u043f\u043b\u0435\u043d \u043d\u0435\u043f\u0440\u0438\u044f\u0442\u0435\u043b\u0435\u043c, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0440\u0430\u043d\u0435\u043d\u044b\u0445 \u0438 \u043a\u043e\u043d\u0442\u0443\u0436\u0435\u043d\u043d\u044b\u0445, \u0441 1 \u0438\u044e\u043b\u044f \u043f\u043e 15 \u0438\u044e\u043b\u044f 1916 \u0433., \u0410\u0432\u0442\u043e\u0440: 122-\u0439 \u043f\u0435\u0445\u043e\u0442\u043d\u044b\u0439 \u0422\u0430\u043c\u0431\u043e\u0432\u0441\u043a\u0438\u0439 \u043f\u043e\u043b\u043a, 1916-07-24<br />\nhttps://gwar.mil.ru/heroes/document/10000331/?page_id=10127038\n</p>\n<p>\n&nbsp;\n</p>\n</div>\n</div>",
